Public class ETGCocoaShipmentUIBuilder extends SrsReportDataContractUIBuilder
{
    ETGCocoaShipmentContract             ETGCocoaShipmentContract;
    FormStringControl                       dimensionControl;

    DialogField                         fromDt,ToDt,CustId,Item,InvId;

}

Method.Source:
public void LookupCustId(FormStringControl _control)
{
    Query                   query = new Query();
    container               conCustId;
    QueryBuildDataSource    qbds;
    QueryBuildRange         qbr;

    qbds        = query.addDataSource(tableNum(CustTable));
    qbds.addSelectionField(fieldNum(CustTable,AccountNum));
    SysLookupMultiSelectGrid::lookup(query,_control,_control,_control,conCustId);
}

public void LookupItemId(FormStringControl _control)
{
    Query                   query = new Query();
    container               conItemId;
    QueryBuildDataSource    qbds;
    QueryBuildRange         qbr;

    qbds        = query.addDataSource(tableNum(InventTable));
    qbds.addSelectionField(fieldNum(InventTable,ItemId));
    SysLookupMultiSelectGrid::lookup(query,_control,_control,_control,conItemId);
}

public void LookupInvoiceId(FormStringControl _control)
{
    Query                   query = new Query();
    container               conInvId;
    QueryBuildDataSource    qbds;
    QueryBuildRange         qbr;

    qbds        = query.addDataSource(tableNum(CustInvoiceJour));
    qbds.addSelectionField(fieldNum(CustInvoiceJour,InvoiceId));
    SysLookupMultiSelectGrid::lookup(query,_control,_control,_control,conInvId);
}

public void build()
{
    int i;
    ETGCocoaShipmentContract   contract;
    contract = this.dataContractObject() as ETGCocoaShipmentContract;
    fromDt = this.addDialogField(methodStr(ETGCocoaShipmentContract, parmfromdate),contract);
    ToDt = this.addDialogField(methodStr(ETGCocoaShipmentContract, parmtodate),contract);
    CustId = this.addDialogField(methodStr(ETGCocoaShipmentContract, parmCustAccount),contract);
    InvId = this.addDialogField(methodStr(ETGCocoaShipmentContract, parmInvoiceId),contract);
    Item = this.addDialogField(methodStr(ETGCocoaShipmentContract, parmItemId),contract);

}

public void postBuild()
{
    ETGCocoaShipmentContract   contract;
    super();
    contract = this.dataContractObject() as ETGCocoaShipmentContract;
    fromDt = this.bindInfo().getDialogField(contract,methodStr(ETGCocoaShipmentContract, parmfromdate));
    ToDt = this.bindInfo().getDialogField(contract,methodStr(ETGCocoaShipmentContract, parmtodate));
    CustId = this.bindInfo().getDialogField(contract,methodStr(ETGCocoaShipmentContract, parmCustAccount));

    CustId.registerOverrideMethod(methodStr(FormStringControl, lookup),
    methodStr(ETGCocoaShipmentUIBuilder, lookupCustId),this);
    if (CustId)
    {
        CustId.lookupButton(2);
    }
    item = this.bindInfo().getDialogField(contract,methodStr(ETGCocoaShipmentContract, parmItemId));

    item.registerOverrideMethod(methodStr(FormStringControl, lookup),
    methodStr(ETGCocoaShipmentUIBuilder, lookupItemId),this);
    if (item)
    {
        item.lookupButton(2);
    }
    InvId = this.bindInfo().getDialogField(contract,methodStr(ETGCocoaShipmentContract, parmInvoiceId));

    InvId.registerOverrideMethod(methodStr(FormStringControl, lookup),
    methodStr(ETGCocoaShipmentUIBuilder, LookupInvoiceId),this);
    if (InvId)
    {
        InvId.lookupButton(2);
    }
}
